/**
 * Milestone-1 ceiling benchmark (ANALYTICS representative) for the Janino codegen plan
 * (plans/lmdb-native-engine/17-janino-whole-stage-codegen.md): ANALYTICS query 11 — the predicate selectivity profile
 * (full-scan GROUP BY ?p with COUNT(*) and two COUNT(DISTINCT)) — engine vs the hand-written ideal fused kernel.
 * Requires the fixed theme benchmark store (built by {@link ThemeQueryBenchmark}) at
 * {@code core/sail/lmdb/target/lmdb-theme-query-benchmark/complete}; the setup fails fast when it is missing rather
 * than rebuilding it. Kernel correctness is pinned on FOAF data by {@link JaninoCeilingParityTest}; here the setup
 * additionally asserts the expected 100 result rows.
 */
@State(Scope.Benchmark)
@Warmup(iterations = 3, batchSize = 1, time = 5, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode({ Mode.AverageTime })
@Fork(value = 1, jvmArgs = { "-Xms1G", "-Xmx16G" })
@Measurement(iterations = 3, batchSize = 1, time = 5, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
public class JaninoCeilingAnalyticsBenchmark {

	private static final String PREDICATE_SELECTIVITY = "PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>\n"
			+ "PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>\n"
			+ "SELECT ?p (COUNT(*) AS ?statements) (COUNT(DISTINCT ?s) AS ?distinctSubjects) "
			+ "(COUNT(DISTINCT ?o) AS ?distinctObjects) WHERE {\n"
			+ "  ?s ?p ?o .\n"
			+ "}\n"
			+ "GROUP BY ?p\n"
			+ "ORDER BY DESC(?statements) ?p\n";

	private SailRepository repository;
	private SailDataset dataset;
	private NativeLmdbQuerySource source;

	private static File storeDirectory() {
		File inModule = new File("target", "lmdb-theme-query-benchmark");
		if (new File("src/main/java/org/eclipse/rdf4j/sail/lmdb").isDirectory()) {
			return new File(inModule, "complete");
		}
		return new File("core/sail/lmdb/target/lmdb-theme-query-benchmark/complete");
	}

	@Setup(Level.Trial)
	public void setup() throws Exception {
		File storeDir = storeDirectory();
		if (!new File(storeDir, "triples").isDirectory()) {
			throw new IllegalStateException("Fixed theme store missing at " + storeDir.getAbsolutePath()
					+ "; run ThemeQueryBenchmark once to build it");
		}
		System.setProperty("rdf4j.lmdb.nativeQueryEngine.enabled", "true");

		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc,posc");
		config.setSketchEstimatorEnabled(false);
		config.setForceSync(false);
		config.setValueDBSize(1_073_741_824L);
		config.setTripleDBSize(config.getValueDBSize());
		repository = new SailRepository(new LmdbStore(storeDir, config));
		repository.init();

		dataset = JaninoCeilingKernels.openDataset((LmdbStore) repository.getSail());
		source = (NativeLmdbQuerySource) dataset;

		long[][] rows = JaninoCeilingKernels.predicateSelectivity(source);
		if (rows.length != 100) {
			throw new IllegalStateException("expected 100 predicate rows, got " + rows.length);
		}
	}

	@TearDown(Level.Trial)
	public void tearDown() throws Exception {
		if (dataset != null) {
			dataset.close();
		}
		if (repository != null) {
			repository.shutDown();
		}
	}

	@Benchmark
	public long enginePredicateSelectivity() {
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult result = connection
						.prepareTupleQuery(QueryLanguage.SPARQL, PREDICATE_SELECTIVITY)
						.evaluate()) {
			long count = 0L;
			while (result.hasNext()) {
				result.next();
				count++;
			}
			return count;
		}
	}

	@Benchmark
	public int fusedPredicateSelectivity() throws Exception {
		long[][] rows = JaninoCeilingKernels.predicateSelectivity(source);
		List<String> lines = JaninoCeilingKernels.formatPredicateSelectivity(rows, source);
		return lines.size();
	}
}
